 30	void fill_eNB_dlsch_MCH(PHY_VARS_eNB *eNB,int mcs,int ndi,int rvidx)
 31	{
 32	
 33	  LTE_eNB_DLSCH_t *dlsch = eNB->dlsch_MCH;
 34	  LTE_DL_FRAME_PARMS *frame_parms=&eNB->frame_parms;
 35	
 36	  //  dlsch->rnti   = M_RNTI;
 37	  dlsch->harq_processes[0]->mcs   = mcs;
 38	  //  dlsch->harq_processes[0]->Ndi   = ndi;
 39	  dlsch->harq_processes[0]->rvidx = rvidx;
 40	  dlsch->harq_processes[0]->Nl    = 1;
 41	  dlsch->harq_processes[0]->TBS   = TBStable[get_I_TBS(dlsch->harq_processes[0]->mcs)][frame_parms->N_RB_DL-1];
 42	  //  dlsch->harq_ids[subframe]       = 0;
 43	  dlsch->harq_processes[0]->nb_rb = frame_parms->N_RB_DL;
 44	
 45	  switch(frame_parms->N_RB_DL) {
 46	  case 6:
 47	    dlsch->harq_processes[0]->rb_alloc[0] = 0x3f;
 48	    break;
 49	
 50	  case 25:
 51	    dlsch->harq_processes[0]->rb_alloc[0] = 0x1ffffff;
 52	    break;
 53	
 54	  case 50:
 55	    dlsch->harq_processes[0]->rb_alloc[0] = 0xffffffff;
 56	    dlsch->harq_processes[0]->rb_alloc[1] = 0x3ffff;
 57	    break;
 58	
 59	  case 100:
 60	    dlsch->harq_processes[0]->rb_alloc[0] = 0xffffffff;
 61	    dlsch->harq_processes[0]->rb_alloc[1] = 0xffffffff;
 62	    dlsch->harq_processes[0]->rb_alloc[2] = 0xffffffff;
 63	    dlsch->harq_processes[0]->rb_alloc[3] = 0xf;
 64	    break;
 65	  }
 66	
 67	}
